for (uint256 i; i < n; ++i) {
    IPEMCertChainLib.ECSha256Certificate memory issuer;
    if (i == n - 1) {
        // rootCA
        issuer = certs[i];
    } else {
        issuer = certs[i + 1];
        if (i == n - 2) {
            certRevoked = _serialNumIsRevoked[uint256(IPEMCertChainLib.CRL.ROOT)][certs[i].serialNumber];
        } else if (certs[i].isPck) {
            certRevoked = _serialNumIsRevoked[uint256(IPEMCertChainLib.CRL.PCK)][certs[i].serialNumber];
        }
        if (certRevoked) { break; }
    }

    certNotExpired = block.timestamp > certs[i].notBefore && block.timestamp < certs[i].notAfter;
    if (!certNotExpired) { break; }

    verified = sigVerifyLib.verifyES256Signature(
        certs[i].tbsCertificate, certs[i].signature, issuer.pubKey
    );
    if (!verified) { break; }

    bytes32 issuerPubKeyHash = keccak256(issuer.pubKey);

    if (issuerPubKeyHash == ROOTCA_PUBKEY_HASH) {
        certChainCanBeTrusted = true;
        break;
    }
}
